INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (11, '流量闭环', '新版本关联', '新品绑定到老品New Model, 提升转化', 80, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (11, '流量闭环', '新版本关联', '占坑，防止流量丢失（另一个角度的提高转化）', 81, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (11, '流量闭环', '新版本关联', '新版本价格更高，提升本品转化', 82, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (11, '流量闭环', '捆绑，buy together', '配套产品捆绑销售，提高转化（羽毛球/羽毛球拍）', 83, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (11, '流量闭环', '捆绑，buy together', '设置捆绑优惠，提高转化', 84, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (11, '流量闭环', '定位广告', '有但有临界值；在临界值内占据更多坑位，提升整体转化', 85, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (12, '品牌故事', '关联产品推荐', '流量闭环，色调风格统一', 86, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (12, '品牌故事', '品牌形象', '品牌背书-认证，成绩展示', 87, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (12, '品牌故事', '卖点介绍', '核心卖点多次加强输出', 88, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (12, '品牌故事', '卖家介绍', '体现专业性，讲述品牌理念和产品设计初衷', 89, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (13, 'A+', '整体性', '符合品牌调性，色调风格统一，弱化页面的切片感，遵循图片逻辑，更多品牌化特色', 90, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (13, 'A+', '兼顾PC和手机端用户体验', '在电脑端及移动端均能让顾客流畅浏览，避免图片展示不到位卖点表达不清晰的问题', 91, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (13, 'A+', '卖点展示形式更多样', '需要包含的板块（banner+核心卖点+场景集合+问答+流量闭环框+安装视频（可选）+品牌化视频等）巧用模块，提升A+观感和可玩性；模块服务于卖点，有空间做更多更详细的卖点表达，避免卖点堆砌重复', 92, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (13, 'A+', '是否包含对比图表？', '制作与竞品的参数对比表，突出核心优势', 93, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (13, 'A+', '是否设计了清晰的故事线？', 'A+内容应有逻辑：吸引→展示卖点→解决疑虑→建立信任', 94, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (13, 'A+', '页面更大，场景化', '让买家身临其境，提高对产品的信任与喜爱', 95, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (13, 'A+', '视频', '智能产品可以放很多功能的介绍操作视频，帮助用户直观感受产品功能；也可以上传卖点视频来动态宣传每一个卖点', 96, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (13, 'A+', '售后方式', '亚马逊对视频审核较弱，视频最后几秒附上售后方式，提高客户售后联系频率', 97, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (13, 'A+', 'QA', '将买家关注的热点问题突出展示，让顾客一目了然，在收到前就能解决相关问题', 98, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (13, 'A+', '产品闭环', '关联产品推荐、同类产品推荐', 99, NULL, 0);

